CREATE EXTENSION IF NOT EXISTS vector;
CREATE TABLE customers(id BIGSERIAL PRIMARY KEY,name TEXT UNIQUE NOT NULL,description TEXT DEFAULT '',archived BOOLEAN DEFAULT false,created_at TIMESTAMPTZ DEFAULT now(),updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE global_provider_config(id BIGINT PRIMARY KEY DEFAULT 1,llm_provider TEXT DEFAULT 'mock',llm_model TEXT DEFAULT 'mock-grounded-v1',embedding_provider TEXT DEFAULT 'mock',embedding_model TEXT DEFAULT 'mock-hash-v1',ai_base_url TEXT,ai_api_key TEXT,embedding_base_url TEXT,embedding_api_key TEXT,provider_display_name TEXT DEFAULT '',custom_headers TEXT,chat_endpoint_path TEXT DEFAULT '/chat/completions',embedding_endpoint_path TEXT DEFAULT '/embeddings',openai_compatible_mode BOOLEAN DEFAULT true,temperature DOUBLE PRECISION DEFAULT .1,top_p DOUBLE PRECISION DEFAULT 1,top_k INTEGER DEFAULT 4,max_tokens INTEGER DEFAULT 500,timeout INTEGER DEFAULT 60,retry_count INTEGER DEFAULT 2,chunk_size INTEGER DEFAULT 900,chunk_overlap INTEGER DEFAULT 120,prompt_instructions TEXT);
CREATE TABLE providers_config(id BIGSERIAL PRIMARY KEY,customer_id BIGINT UNIQUE NOT NULL REFERENCES customers(id) ON DELETE CASCADE,is_override BOOLEAN DEFAULT false,llm_provider TEXT DEFAULT 'mock',llm_model TEXT DEFAULT 'mock-grounded-v1',embedding_provider TEXT DEFAULT 'mock',embedding_model TEXT DEFAULT 'mock-hash-v1',ai_base_url TEXT,ai_api_key TEXT,embedding_base_url TEXT,embedding_api_key TEXT,provider_display_name TEXT DEFAULT '',custom_headers TEXT,chat_endpoint_path TEXT DEFAULT '/chat/completions',embedding_endpoint_path TEXT DEFAULT '/embeddings',openai_compatible_mode BOOLEAN DEFAULT true,temperature DOUBLE PRECISION DEFAULT .1,top_p DOUBLE PRECISION DEFAULT 1,top_k INTEGER DEFAULT 4,max_tokens INTEGER DEFAULT 500,timeout INTEGER DEFAULT 60,retry_count INTEGER DEFAULT 2,chunk_size INTEGER DEFAULT 900,chunk_overlap INTEGER DEFAULT 120,prompt_instructions TEXT);
CREATE TABLE documents(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,name TEXT NOT NULL,category TEXT NOT NULL,product_name TEXT NOT NULL,product_version TEXT DEFAULT '',product_line TEXT DEFAULT '',document_collection TEXT DEFAULT 'default',enabled BOOLEAN DEFAULT true,kind TEXT DEFAULT 'knowledge',path TEXT NOT NULL,status TEXT NOT NULL,size_bytes BIGINT DEFAULT 0,mime_type TEXT,extracted_text_length INTEGER DEFAULT 0,embedding_count INTEGER DEFAULT 0,vector_count INTEGER DEFAULT 0,embedding_provider TEXT,embedding_model TEXT,embedding_dimension INTEGER DEFAULT 0,settings_source TEXT DEFAULT 'global_default',indexed_chunk_size INTEGER DEFAULT 0,indexed_chunk_overlap INTEGER DEFAULT 0,last_indexed_at TIMESTAMPTZ,error_message TEXT,created_at TIMESTAMPTZ DEFAULT now(),updated_at TIMESTAMPTZ DEFAULT now());
CREATE INDEX ix_documents_customer ON documents(customer_id);
CREATE TABLE document_chunks(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,document_id BIGINT NOT NULL REFERENCES documents(id) ON DELETE CASCADE,content TEXT NOT NULL,embedding JSONB NOT NULL,ordinal INTEGER NOT NULL,page_number INTEGER);
CREATE INDEX ix_chunks_customer_document ON document_chunks(customer_id,document_id);
CREATE TABLE questionnaires(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,name TEXT NOT NULL,product_name TEXT NOT NULL,product_version TEXT DEFAULT '',product_line TEXT DEFAULT '',document_collection TEXT DEFAULT 'default',selected_categories JSONB DEFAULT '[]',status TEXT NOT NULL,path TEXT,created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE questions(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,questionnaire_id BIGINT NOT NULL REFERENCES questionnaires(id) ON DELETE CASCADE,text TEXT NOT NULL,ordinal INTEGER NOT NULL,retrieval_cache JSONB,retrieval_cache_key TEXT);
CREATE TABLE answers(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,question_id BIGINT UNIQUE NOT NULL REFERENCES questions(id) ON DELETE CASCADE,text TEXT NOT NULL,confidence DOUBLE PRECISION,status TEXT NOT NULL,sources JSONB NOT NULL,debug_data JSONB DEFAULT '{}',classification_reason TEXT DEFAULT '',golden BOOLEAN DEFAULT false,global_approved BOOLEAN DEFAULT false,reviewer TEXT DEFAULT '',approved_at TIMESTAMPTZ,reused_from_answer_id BIGINT,review_started_at TIMESTAMPTZ DEFAULT now(),review_duration_seconds INTEGER DEFAULT 0,category TEXT DEFAULT 'General',product_name TEXT NOT NULL,product_version TEXT DEFAULT '',product_line TEXT DEFAULT '',document_collection TEXT DEFAULT 'default',evidence_document_ids JSONB DEFAULT '[]',updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE answer_versions(id BIGSERIAL PRIMARY KEY,customer_id BIGINT NOT NULL REFERENCES customers(id) ON DELETE CASCADE,answer_id BIGINT NOT NULL REFERENCES answers(id) ON DELETE CASCADE,version INTEGER NOT NULL,text TEXT NOT NULL,confidence DOUBLE PRECISION,status TEXT NOT NULL,sources JSONB NOT NULL,created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE audit_logs(id BIGSERIAL PRIMARY KEY,customer_id BIGINT REFERENCES customers(id) ON DELETE CASCADE,action TEXT NOT NULL,entity_type TEXT NOT NULL,entity_id BIGINT,details JSONB,created_at TIMESTAMPTZ DEFAULT now());
CREATE INDEX ix_audit_customer_created ON audit_logs(customer_id,created_at DESC);
